parameters.query:
CREATE TABLE IF NOT EXISTS sessions (
  session_id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  projet_id UUID REFERENCES projets(projet_id) ON DELETE SET NULL,
  porteur_id VARCHAR(100) NOT NULL,
  historique JSONB DEFAULT '[]',
  etat_courant VARCHAR(50) DEFAULT 'accueil',
  nb_questions INT DEFAULT 0,
  score_global FLOAT DEFAULT 0,
  porteur_confirme BOOLEAN DEFAULT false,
  fiche_complete BOOLEAN DEFAULT false,
  created_at TIMESTAMP DEFAULT NOW(),
  updated_at TIMESTAMP DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS idx_sessions_porteur_id ON sessions(porteur_id);
CREATE INDEX IF NOT EXISTS idx_sessions_etat ON sessions(etat_courant);

COMMENT ON COLUMN sessions.etat_courant IS 'accueil | clarification | evaluation | structuration | archive';
COMMENT ON COLUMN sessions.porteur_id IS 'Telegram chat_id du porteur';

CREATE TABLE IF NOT EXISTS executions_log (
  id BIGSERIAL PRIMARY KEY,
  session_id UUID,
  agent_id VARCHAR(50),
  input_tokens INT DEFAULT 0,
  output_tokens INT DEFAULT 0,
  latence_ms INT DEFAULT 0,
  statut VARCHAR(20) DEFAULT 'ok',
  erreur TEXT,
  created_at TIMESTAMP DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS idx_execlog_session_id ON executions_log(session_id);
CREATE INDEX IF NOT EXISTS idx_execlog_created_at ON executions_log(created_at DESC);

