parameters.jsCode:
// CERVEAU — Classificateur déterministe
// Phase 0 : Hello World — pass-through
// Phase 1+ : lire session DB et router

const message = $json.message;
const porteur_id = String(message?.from?.id || message?.chat?.id);
const chat_id = String(message?.chat?.id);
const text = message?.text || '';

// Commandes spéciales
if (text === '/start' || text === '/reset') {
  return {
    json: {
      chat_id,
      porteur_id,
      text,
      route: 'RESET',
      reponse: '👋 Bienvenue sur K3rn.labs.\n\nPartagez votre idée — notre équipe d\'experts IA l\'analyse, la clarifie et la structure pour vous.\n\nCommencez par décrire votre idée en quelques phrases.'
    }
  };
}

// Phase 0 : routage par défaut → RÉCEPTEUR
return {
  json: {
    chat_id,
    porteur_id,
    text,
    route: 'RECEPTEUR',
    reponse: '✅ Message reçu par K3rn.labs.\n\n_[Phase 0 — Hello World OK]_'
  }
};

